def compute_score() -> tuple[str, float]:
    """
    Checks if the main chart or image on slide 2 has been moved to the left side of the slide.
    """
    # Use vision model to check for chart/image placement
    slide_num = 2
    try:
        mod_img = [s.image_path for s in modified_ppt_screenshots if s.slide_number == slide_num][0]
        prompt = "Is the graph chart positioned in the left half of the slide? Reply Yes or No."
        result = vlm_call(prompt, [mod_img], temperature=0.0, max_tokens=5)
        if 'yes' in result.lower():
            return ("Chart/image is on the left half of the slide.", 1.0)
        else:
            return ("Chart/image is not on the left half of the slide.", 0.0)
    except IndexError:
        return (f"Slide {slide_num} not found in modified presentation.", 0.0)
    except Exception as e:
        return (f"Unable to verify chart/image placement: {e}", 0.0)

